import React, { useState, useMemo } from "react";

interface TreeViewProps {
  searchTerm: string;
  dateFilter: string;
}

const TreeView: React.FC<TreeViewProps> = ({ searchTerm, dateFilter }) => {
  const [expandedNodes, setExpandedNodes] = useState<string[]>(['raw-files', 'transcriptions']);

  const toggleNode = (nodeId: string) => {
    setExpandedNodes(prev =>
      prev.includes(nodeId)
        ? prev.filter(id => id !== nodeId)
        : [...prev, nodeId]
    );
  };

  // Données de démo
  const treeData = {
    'raw-files': {
      label: 'Fichiers bruts',
      icon: 'fa-folder text-yellow-500',
      count: 12,
      children: [
        { id: 'rf-1', label: 'audio_001.mp3', icon: 'fa-music text-blue-500', date: '2025-01-15' },
        { id: 'rf-2', label: 'audio_002.mp3', icon: 'fa-music text-blue-500', date: '2025-01-15' },
        { id: 'rf-3', label: 'scan_chapitre1.pdf', icon: 'fa-file-pdf text-red-500', date: '2025-01-14' },
      ]
    },
    'transcriptions': {
      label: 'Transcriptions',
      icon: 'fa-file-alt text-green-500',
      count: 5,
      children: [
        { id: 't-1', label: 'Transcription A', icon: 'fa-file-lines text-green-500', date: '2025-01-15', parents: ['audio_001.mp3', 'audio_002.mp3'] },
        { id: 't-2', label: 'Transcription B', icon: 'fa-file-lines text-green-500', date: '2025-01-14', parents: ['scan_chapitre1.pdf'] },
      ]
    },
    'book-projects': {
      label: 'Projets de livre',
      icon: 'fa-book text-purple-500',
      count: 2,
      children: [
        { id: 'bp-1', label: 'Livre 1', icon: 'fa-book text-purple-500', date: '2025-01-15', parents: ['Transcription A', 'Transcription B'] },
      ]
    },
    'proofreading-v1': {
      label: 'Relecture 1',
      icon: 'fa-eye text-amber-500',
      count: 2,
      children: [
        { id: 'pr1-1', label: 'Relecture 1 - Livre 1', icon: 'fa-eye text-amber-500', date: '2025-01-15' },
      ]
    },
    'proofreading-v2': {
      label: 'Relecture 2',
      icon: 'fa-eye-double text-red-500',
      count: 2,
      children: [
        { id: 'pr2-1', label: 'Relecture 2 - Livre 1', icon: 'fa-eye-double text-red-500', date: '2025-01-15' },
      ]
    },
  };

  // ✅ FILTRAGE
  const filteredTreeData = useMemo(() => {
    const filtered: any = {};
    
    Object.entries(treeData).forEach(([nodeId, node]: [string, any]) => {
      const filteredChildren = node.children.filter((child: any) => {
        const matchesSearch = child.label.toLowerCase().includes(searchTerm.toLowerCase());
        let matchesDate = true;
        
        if (dateFilter === "today") {
          matchesDate = child.date === new Date().toISOString().split('T')[0];
        } else if (dateFilter === "week") {
          const weekAgo = new Date();
          weekAgo.setDate(weekAgo.getDate() - 7);
          matchesDate = new Date(child.date) >= weekAgo;
        } else if (dateFilter === "month") {
          const monthAgo = new Date();
          monthAgo.setMonth(monthAgo.getMonth() - 1);
          matchesDate = new Date(child.date) >= monthAgo;
        }
        
        return matchesSearch && matchesDate;
      });
      
      if (filteredChildren.length > 0 || searchTerm === "") {
        filtered[nodeId] = {
          ...node,
          children: searchTerm === "" ? node.children : filteredChildren,
          count: filteredChildren.length
        };
      }
    });
    
    return filtered;
  }, [searchTerm, dateFilter]);

  return (
    <div className="space-y-2">
      <h2 className="text-lg font-semibold text-gray-900 dark:text-white mb-4 flex items-center justify-between">
        <div className="flex items-center">
          <i className="fas fa-sitemap mr-2 text-purple-600"></i>
          Arborescence du Flux Éditorial
        </div>
        <span className="text-sm text-gray-500 dark:text-gray-400">
          {Object.values(filteredTreeData).reduce((acc: number, node: any) => acc + node.count, 0)} éléments
        </span>
      </h2>
      
      <div className="bg-gray-50 dark:bg-gray-700/30 rounded-lg p-4">
        {Object.entries(filteredTreeData).map(([nodeId, node]: [string, any]) => (
          <div key={nodeId} className="mb-2">
            <button
              onClick={() => toggleNode(nodeId)}
              className="w-full flex items-center justify-between p-3 hover:bg-gray-100 dark:hover:bg-gray-600 rounded-lg transition-colors"
            >
              <div className="flex items-center gap-3">
                <i className={`fas ${node.icon} text-lg`}></i>
                <span className="font-medium text-gray-900 dark:text-white">
                  {node.label}
                </span>
                <span className="px-2 py-0.5 text-xs bg-gray-200 dark:bg-gray-600 text-gray-700 dark:text-gray-300 rounded-full">
                  {node.count}
                </span>
              </div>
              <i className={`fas fa-chevron-${expandedNodes.includes(nodeId) ? 'down' : 'right'} text-gray-400`}></i>
            </button>
            
            {expandedNodes.includes(nodeId) && node.children && (
              <div className="ml-8 mt-2 space-y-1 border-l-2 border-gray-200 dark:border-gray-600 pl-4">
                {node.children.map((child: any) => (
                  <div
                    key={child.id}
                    className="flex items-center gap-3 p-2 hover:bg-gray-100 dark:hover:bg-gray-600 rounded-lg transition-colors cursor-pointer"
                  >
                    <i className={`fas ${child.icon} text-sm`}></i>
                    <span className="text-sm text-gray-700 dark:text-gray-300">
                      {child.label}
                    </span>
                    {child.parents && (
                      <span className="text-xs text-gray-400 ml-2">
                        ← {child.parents.join(' + ')}
                      </span>
                    )}
                    <span className="text-xs text-gray-500 dark:text-gray-400 ml-auto">
                      {child.date}
                    </span>
                  </div>
                ))}
              </div>
            )}
          </div>
        ))}
      </div>
    </div>
  );
};

export default TreeView;
